import Comment from '@kyokuya/react-comment'
import type { PostItem } from '@kyokuya/react-layout-post'
import type {
  Definition,
  EcmaImport,
  FootnoteDefinition,
  HeadingToc,
  HeadingTocNode,
  Root,
} from '@yozora/ast'
import { YozoraMarkdownContext } from '@yozora/react-markdown'
import type { APlayerOptions } from 'aplayer'
import React, { useMemo } from 'react'
import Seo from '@/component/seo'
import type { TocItemData } from '@/component/toc'
import Toc from '@/component/toc'
import useActivatedIdentifier from '@/core/hook/useActivatedIdentifier'
import { Layout } from '../component/Layout'
import { PostContent } from '../component/PostContent'
import { PostLayoutContextProvider } from '../context/Provider'
import LayoutPostMarkdownProvider from './_MarkdownProvider'

export interface PostPageQueryContext {
  /**
   * Url of pagination pages.
   */
  paginationUrl: string
  /**
   * Home url
   * @default '/'
   */
  homeUrl?: string
}

export interface PostPageProps extends PostPageQueryContext {
  content: {
    title: string
    description: string
    createAt: string
    updateAt: string
    timeToRead: string
    toc: HeadingToc
    ast: Root
    categories: string[][]
    tags: string[]
    ecmaImports: EcmaImport[]
    definitionMap: Record<string, Definition>
    footnoteDefinitionMap: Record<string, FootnoteDefinition>
    frontmatter2: {
      aplayer?: APlayerOptions
      wechatThumbnail?: string
    }
    fields: {
      slug: string
    }
  }
  previous?: {
    title: string
    fields: {
      slug: string
    }
  }
  next?: {
    title: string
    fields: {
      slug: string
    }
  }
  postItems: {
    nodes: PostItem[]
  }
}

/**
 * Render a blog post.
 *
 * @param props
 * @returns
 */
export function PostPage(props: PostPageProps): React.ReactElement {
  const {
    title,
    createAt,
    timeToRead,
    description,
    toc,
    tags,
    ast,
    ecmaImports,
    definitionMap,
    footnoteDefinitionMap,
    frontmatter2,
    fields,
  } = props.content
  const { slug } = fields!
  const { paginationUrl, previous, next } = props
  const postItems = (props.postItems.nodes ?? []) as PostItem[]

  const {
    activatedIdentifier,
    refreshActivatedIdentifier,
    pauseWatchingScroll,
  } = useActivatedIdentifier('yozora-heading--toc', 0)

  const tocNodes = useMemo<TocItemData[]>((): TocItemData[] => {
    const results: TocItemData[] = []
    function collectTocData(node: HeadingTocNode, cur: number): void {
      const data: TocItemData = {
        depth: cur,
        identifier: encodeURIComponent(node.identifier),
        title: (
          <YozoraMarkdownContext.Consumer>
            {({ renderYozoraNodes }) => renderYozoraNodes(node.contents)}
          </YozoraMarkdownContext.Consumer>
        ),
      }
      results.push(data)
      if (node.children != null) {
        node.children.forEach(node => collectTocData(node, cur + 1))
      }
    }

    toc.children.forEach(node => collectTocData(node, 1))
    return results
  }, [toc.children])

  return (
    <PostLayoutContextProvider posts={postItems}>
      <LayoutPostMarkdownProvider
        ecmaImports={ecmaImports}
        definitionMap={definitionMap}
        footnoteDefinitionMap={footnoteDefinitionMap}
      >
        <Layout
          onScroll={refreshActivatedIdentifier}
          paginationUrl={paginationUrl}
          head={
            <React.Fragment>
              <Seo title={title} description={description} />
            </React.Fragment>
          }
          content={
            <PostContent
              title={title}
              createAt={createAt}
              timeToRead={timeToRead}
              tags={tags}
              ast={ast}
              slug={slug}
              aplayer={frontmatter2.aplayer}
              previous={previous}
              next={next}
            />
          }
          footer={<Comment className="kyokuya-post__frosted-glass-panel" />}
          nav={
            tocNodes.length > 0 && (
              <Toc
                activatedIdentifier={activatedIdentifier}
                nodes={tocNodes}
                pauseWatchingScroll={pauseWatchingScroll}
              />
            )
          }
        />
      </LayoutPostMarkdownProvider>
    </PostLayoutContextProvider>
  )
}

PostPage.displayName = 'KyokuyaLayoutPostPostPage'
export default PostPage
