import debounce from '@kyokuya/_shared/util/debounce'
import { PostLayoutContext } from '@kyokuya/react-layout-post'
import type { PostItem } from '@kyokuya/react-layout-post'
import Link from '@kyokuya/react-link'
import { IconButton, Input, Switch, withStyles } from '@material-ui/core'
import CancelIcon from '@material-ui/icons/ClearOutlined'
import SearchIcon from '@material-ui/icons/SearchOutlined'
import cn from 'clsx'
import Fuse from 'fuse.js'
import PropTypes from 'prop-types'
import React, {
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
} from 'react'
import { PostLayoutActionsType } from '../context/actions'

const TagListSwitch = withStyles({
  switchBase: {
    color: '#f6e1cc',
    '&$checked': {
      color: '#eda090',
    },
    '&$checked + $track': {
      backgroundColor: '#eda090',
    },
  },
  checked: {},
  track: {},
})(Switch)

export interface SearchPanelProps {
  /**
   * CSS class name
   */
  className?: string
}

// Search result item.
export type SearchResultItem = Fuse.FuseResult<PostItem>

export const SearchPanel: React.FC<SearchPanelProps> = props => {
  const { searchingKeyword, tags, posts, dispatch } =
    useContext(PostLayoutContext)
  const [keyword, setKeyword] = useState<string>(searchingKeyword)
  const [tagListVisible, setTagListVisible] = useState<boolean>(false)
  const [searchingResult, setSearchingResult] = useState<
    ReadonlyArray<SearchResultItem>
  >([])

  const syncSearchingKeyword = useCallback<(keyword: string) => void>(
    (keyword: string): void =>
      dispatch({
        type: PostLayoutActionsType.SEARCH_REQUEST,
        payload: { keyword },
      }),
    [dispatch],
  )

  const search = useMemo(() => {
    const fullItems: SearchResultItem[] = posts.map((item, index) => ({
      item,
      matches: [],
      score: 1,
      refIndex: index,
    }))

    const titleSearcher = new Fuse<PostItem>(posts, {
      includeScore: true,
      findAllMatches: true,
      keys: ['title'],
    })

    const tagSearcher = new Fuse<PostItem>(posts, {
      includeScore: true,
      threshold: 0.4,
      keys: ['tags'],
    })

    const _search = (keyword: string): ReadonlyArray<SearchResultItem> => {
      if (keyword.length <= 0) return fullItems
      if (keyword[0] === '#') {
        if (keyword.length <= 0) return fullItems
        return tagSearcher.search(keyword.slice(1))
      }
      return titleSearcher.search(keyword)
    }

    const search = debounce<string, void>((keyword: string) => {
      const result = _search(keyword)
      setSearchingResult(result)
      syncSearchingKeyword(keyword)
    }, 100)

    setSearchingResult(fullItems)
    return search
  }, [posts, setSearchingResult, syncSearchingKeyword])

  const handleKeywordChange = (value: string): void => {
    if (value === keyword) return

    setKeyword(value)
    const resolvedKeyword = value.trim()
    if (resolvedKeyword === keyword.trim()) return
    search(resolvedKeyword)
  }

  // Reset keyword if the one stored in context changed.
  useEffect(() => {
    handleKeywordChange(searchingKeyword)
  }, [searchingKeyword])

  const { className } = props
  return (
    <div className={cn('kyokuya-post-search-panel', className)}>
      <Input
        className="kyokuya-post-search-panel__input"
        type="input"
        value={keyword}
        placeholder="Searching post..."
        autoFocus={true}
        onChange={e => handleKeywordChange(e.target.value)}
        endAdornment={
          <React.Fragment>
            <SearchIcon className={cn({ hidden: keyword.length > 0 })} />
            <IconButton
              className={cn({ hidden: keyword.length <= 0 })}
              onClick={() => handleKeywordChange('')}
            >
              <CancelIcon />
            </IconButton>
          </React.Fragment>
        }
      />
      <div className="kyokuya-post-search-panel__main">
        <div className="kyokuya-post-search-panel__tags-switch">
          <span onClick={() => setTagListVisible(v => !v)}>tags</span>
          <TagListSwitch
            checked={tagListVisible}
            onChange={() => setTagListVisible(v => !v)}
          />
        </div>
        <div
          className={cn('kyokuya-post-search-panel__tags', {
            hidden: !tagListVisible,
          })}
        >
          {tags.map(tag => (
            <span
              key={tag}
              className="kyokuya-post-search-panel__tag"
              onClick={e => {
                e.stopPropagation()
                handleKeywordChange('#' + tag)
              }}
            >
              {tag}
            </span>
          ))}
        </div>
        <ul className="kyokuya-post-search-panel__results">
          {searchingResult.map(({ item }) => (
            <li
              key={item.title}
              className="kyokuya-post-search-panel__result-item"
            >
              <Link
                className="kyokuya-post-search-panel__result-item-header"
                url={item.fields.slug}
                itemProp="url"
              >
                {item.title}
              </Link>
              <div className="kyokuya-post-search-panel__result-item-content">
                <span
                  key="__date"
                  className="kyokuya-post-search-panel__result-item-date"
                >
                  {item.createAt}
                </span>
                🔖&nbsp;
                {item.tags.map(tag => (
                  <span
                    key={tag}
                    className="kyokuya-post-search-panel__result-item-tag"
                    onClick={() => handleKeywordChange('#' + tag)}
                  >
                    #{tag}
                  </span>
                ))}
              </div>
            </li>
          ))}
        </ul>
      </div>
    </div>
  )
}

SearchPanel.propTypes = {
  className: PropTypes.string,
}

SearchPanel.displayName = 'KyokuyaLayoutPostSearchPanel'
export default SearchPanel
