import type React from 'react'
import type { PostLayoutAction } from './actions'
import { PostLayoutActionsType } from './actions'
import type { PostLayoutContextData } from './state'

enum BrightnessLevel {
  // darken
  DARKEN_MIN = 20,
  DARKEN_MAX = 69,
  DARKEN_DEFAULT = 69,

  // light
  LIGHT_MIN = 70,
  LIGHT_MAX = 100,
  LIGHT_DEFAULT = 100,
}

export const reducer: React.Reducer<PostLayoutContextData, PostLayoutAction> = (
  state: PostLayoutContextData,
  action: PostLayoutAction,
): PostLayoutContextData => {
  switch (action.type) {
    case PostLayoutActionsType.SEARCH_REQUEST: {
      const { keyword } = action.payload
      return {
        ...state,
        searchingKeyword: keyword,
        magicPanelVisible: true,
        magicPanelActivated: 'search',
      }
    }
    case PostLayoutActionsType.REFRESH_STATIC_DATA: {
      const { tags, posts } = action.payload
      if (tags === state.tags && posts === state.posts) return state
      return { ...state, tags, posts }
    }
    case PostLayoutActionsType.ACTIVE_MAGIC_PANEL: {
      const { panel } = action.payload
      if (state.magicPanelVisible && panel === state.magicPanelActivated)
        return state
      return { ...state, magicPanelActivated: panel, magicPanelVisible: true }
    }
    case PostLayoutActionsType.TOGGLE_MAGIC_PANEL: {
      const visible = action.payload ?? !state.magicPanelVisible
      if (visible === state.magicPanelVisible) return state
      return { ...state, magicPanelVisible: visible }
    }
    case PostLayoutActionsType.TOGGLE_THEME_BRIGHTNESS: {
      const brightness = Math.max(20, Math.min(100, action.payload))
      if (brightness === state.brightness) return state

      const darken = state.brightness <= BrightnessLevel.DARKEN_MAX
      return { ...state, brightness, darken }
    }
    case PostLayoutActionsType.TOGGLE_THEME_MODE: {
      const mode = action.payload ?? (state.darken ? 'light' : 'darken')
      const brightness: number =
        mode === 'darken'
          ? BrightnessLevel.DARKEN_DEFAULT
          : BrightnessLevel.LIGHT_DEFAULT
      if (brightness === state.brightness) return state
      return { ...state, brightness, darken: mode === 'darken' }
    }
    default:
      return state
  }
}

export default reducer
