import type { MarkdownContextProviderProps } from '@kyokuya/react-markdown'
import { MarkdownContextProvider } from '@kyokuya/react-markdown'
import React, { useContext } from 'react'
import { PostLayoutContext } from '../context/context'

export const LayoutPostMarkdownProvider: React.FC<MarkdownContextProviderProps> =
  props => {
    const { darken } = useContext(PostLayoutContext)
    return (
      <MarkdownContextProvider {...props} darken={props.darken ?? darken} />
    )
  }

export default LayoutPostMarkdownProvider
